public class ShareReceiverActivity extends AppCompatActivity {
    private static final String TAG = "ShareReceiverActivity";
    private static final String PERMISSION_SHARE_RECEIVE = "com.example.permission.SHARE_RECEIVE";
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share_receiver);
        
        Intent intent = getIntent();
        String action = intent.getAction();
        String type = intent.getType();
        
        if (Intent.ACTION_SEND.equals(action) && type != null) {
            if (type.startsWith("image/")) {
                handleSendImage(intent);
            } else if (type.startsWith("text/")) {
                handleSendText(intent);
            }
        }
    }
    
    private void handleSendImage(Intent intent) {
        Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (imageUri != null) {
            if (validateUri(imageUri)) {
                displayImage(imageUri);
            } else {
                showError("Invalid image URI");
            }
        }
    }
    
    private void handleSendText(Intent intent) {
        String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
        if (sharedText != null && !sharedText.isEmpty()) {
            displayText(sharedText);
        }
    }
    
    private boolean validateUri(Uri uri) {
        try {
            if (uri == null) return false;
            
            String scheme = uri.getScheme();
            if (!"content".equals(scheme) && !"file".equals(scheme)) {
                return false;
            }
            
            String authority = uri.getAuthority();
            if (authority == null) return false;
            
            return true;
        } catch (Exception e) {
            Log.e(TAG, "URI validation error", e);
            return false;
        }
    }
    
    private void displayImage(Uri imageUri) {
        ImageView imageView = findViewById(R.id.imageView);
        try {
            Bitmap bitmap = MediaStore.Images.Media.getBitmap(getContentResolver(), imageUri);
            imageView.setImageBitmap(bitmap);
        } catch (IOException e) {
            Log.e(TAG, "Error loading image", e);
            showError("Failed to load image");
        }
    }
    
    private void displayText(String text) {
        TextView textView = findViewById(R.id.textView);
        textView.setText(text);
    }
    
    private void showError(String message) {
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
    }
}